package automaton

import "sort"

// MaximumSupportedLevenshteinDistance is the largest n for which Lucene's
// parametric descriptions exist. Beyond this LevenshteinAutomata returns nil.
const MaximumSupportedLevenshteinDistance = 2

// LevenshteinAutomata constructs DFAs accepting all strings within a given
// edit distance of an input word.
type LevenshteinAutomata struct {
	word         []int
	alphabet     []int
	alphaMax     int
	rangeLower   []int
	rangeUpper   []int
	numRanges    int
	descriptions []parametricDescription
}

// NewLevenshteinAutomataString constructs a LevenshteinAutomata from a Unicode
// string. Set withTranspositions = true to count transpositions as 1 edit.
func NewLevenshteinAutomataString(input string, withTranspositions bool) *LevenshteinAutomata {
	word := []int(nil)
	for _, r := range input {
		word = append(word, int(r))
	}
	return NewLevenshteinAutomata(word, MaxCodePoint, withTranspositions)
}

// NewLevenshteinAutomata constructs a LevenshteinAutomata from a codepoint
// slice with a custom alphabet bound.
func NewLevenshteinAutomata(word []int, alphaMax int, withTranspositions bool) *LevenshteinAutomata {
	l := &LevenshteinAutomata{word: word, alphaMax: alphaMax}
	seen := make(map[int]struct{}, len(word))
	for _, v := range word {
		if v > alphaMax {
			panic("levenshtein: alphabet exceeded")
		}
		seen[v] = struct{}{}
	}
	l.alphabet = make([]int, 0, len(seen))
	for k := range seen {
		l.alphabet = append(l.alphabet, k)
	}
	sort.Ints(l.alphabet)

	l.rangeLower = make([]int, len(l.alphabet)+2)
	l.rangeUpper = make([]int, len(l.alphabet)+2)
	lower := 0
	for _, higher := range l.alphabet {
		if higher > lower {
			l.rangeLower[l.numRanges] = lower
			l.rangeUpper[l.numRanges] = higher - 1
			l.numRanges++
		}
		lower = higher + 1
	}
	if lower <= alphaMax {
		l.rangeLower[l.numRanges] = lower
		l.rangeUpper[l.numRanges] = alphaMax
		l.numRanges++
	}

	if withTranspositions {
		l.descriptions = []parametricDescription{
			nil,
			newLev1TParametricDescription(len(word)),
			newLev2TParametricDescription(len(word)),
		}
	} else {
		l.descriptions = []parametricDescription{
			nil,
			newLev1ParametricDescription(len(word)),
			newLev2ParametricDescription(len(word)),
		}
	}
	return l
}

// ToAutomaton returns a DFA accepting all strings within edit distance n.
// Returns nil when n > MaximumSupportedLevenshteinDistance.
func (l *LevenshteinAutomata) ToAutomaton(n int) *Automaton {
	return l.ToAutomatonWithPrefix(n, "")
}

// ToAutomatonWithPrefix is ToAutomaton with an exact-match prefix prepended.
func (l *LevenshteinAutomata) ToAutomatonWithPrefix(n int, prefix string) *Automaton {
	if n == 0 {
		var word []rune
		for _, cp := range l.word {
			word = append(word, rune(cp))
		}
		return MakeString(prefix + string(word))
	}
	if n >= len(l.descriptions) {
		return nil
	}
	rng := 2*n + 1
	desc := l.descriptions[n]
	numStates := desc.size()

	prefixStates := 0
	for range prefix {
		prefixStates++
	}

	a := NewAutomatonWithCapacity(numStates+prefixStates, numStates*minInt(1+2*n, len(l.alphabet)))
	var lastState int
	lastState = a.CreateState()
	for _, r := range prefix {
		state := a.CreateState()
		a.AddTransition(lastState, state, int(r), int(r))
		lastState = state
	}

	stateOffset := lastState
	if desc.isAccept(0) {
		a.SetAccept(lastState, true)
	}
	for i := 1; i < numStates; i++ {
		state := a.CreateState()
		if desc.isAccept(i) {
			a.SetAccept(state, true)
		}
	}

	for k := 0; k < numStates; k++ {
		xpos := desc.getPosition(k)
		if xpos < 0 {
			continue
		}
		end := xpos + minInt(len(l.word)-xpos, rng)
		for _, ch := range l.alphabet {
			cvec := l.getVector(ch, xpos, end)
			dest := desc.transition(k, xpos, cvec)
			if dest >= 0 {
				a.AddTransition(stateOffset+k, stateOffset+dest, ch, ch)
			}
		}
		dest := desc.transition(k, xpos, 0)
		if dest >= 0 {
			for r := 0; r < l.numRanges; r++ {
				a.AddTransition(stateOffset+k, stateOffset+dest, l.rangeLower[r], l.rangeUpper[r])
			}
		}
	}
	a.FinishState()
	return RemoveDeadStates(a)
}

// getVector returns the characteristic vector X(x, V) where V is word[pos:end].
func (l *LevenshteinAutomata) getVector(x, pos, end int) int {
	vector := 0
	for i := pos; i < end; i++ {
		vector <<= 1
		if l.word[i] == x {
			vector |= 1
		}
	}
	return vector
}

// --- parametric description scaffolding ---

// parametricDescription mirrors Lucene's ParametricDescription abstract class:
// size, isAccept, getPosition, and transition.
type parametricDescription interface {
	size() int
	isAccept(absState int) bool
	getPosition(absState int) int
	transition(state, position, vector int) int
}

// baseParametricDescription holds the shared (w, n, minErrors) fields.
type baseParametricDescription struct {
	w         int
	n         int
	minErrors []int
}

func (d *baseParametricDescription) size() int { return len(d.minErrors) * (d.w + 1) }

func (d *baseParametricDescription) isAcceptInline(absState int) bool {
	state := absState / (d.w + 1)
	offset := absState % (d.w + 1)
	return d.w-offset+d.minErrors[state] <= d.n
}

func (d *baseParametricDescription) getPositionInline(absState int) int {
	return absState % (d.w + 1)
}

// levMasks mirrors Lucene's parametric MASKS table used by unpack().
var levMasks = [...]uint64{
	0x1, 0x3, 0x7, 0xf, 0x1f, 0x3f, 0x7f, 0xff, 0x1ff, 0x3ff, 0x7ff, 0xfff,
	0x1fff, 0x3fff, 0x7fff, 0xffff, 0x1ffff, 0x3ffff, 0x7ffff, 0xfffff,
	0x1fffff, 0x3fffff, 0x7fffff, 0xffffff, 0x1ffffff, 0x3ffffff, 0x7ffffff,
	0xfffffff, 0x1fffffff, 0x3fffffff, 0x7fffffff, 0xffffffff,
	0x1ffffffff, 0x3ffffffff, 0x7ffffffff, 0xfffffffff, 0x1fffffffff,
	0x3fffffffff, 0x7fffffffff, 0xffffffffff, 0x1ffffffffff, 0x3ffffffffff,
	0x7ffffffffff, 0xfffffffffff, 0x1fffffffffff, 0x3fffffffffff,
	0x7fffffffffff, 0xffffffffffff, 0x1ffffffffffff, 0x3ffffffffffff,
	0x7ffffffffffff, 0xfffffffffffff, 0x1fffffffffffff, 0x3fffffffffffff,
	0x7fffffffffffff, 0xffffffffffffff, 0x1ffffffffffffff, 0x3ffffffffffffff,
	0x7ffffffffffffff, 0xfffffffffffffff, 0x1fffffffffffffff,
	0x3fffffffffffffff, 0x7fffffffffffffff,
}

// unpack extracts a value of bitsPerValue bits from the packed long array.
func unpack(data []uint64, index, bitsPerValue int) int {
	bitLoc := int64(bitsPerValue) * int64(index)
	dataLoc := int(bitLoc >> 6)
	bitStart := int(bitLoc & 63)
	if bitStart+bitsPerValue <= 64 {
		return int((data[dataLoc] >> uint(bitStart)) & levMasks[bitsPerValue-1])
	}
	part := 64 - bitStart
	return int(((data[dataLoc] >> uint(bitStart)) & levMasks[part-1]) +
		((data[1+dataLoc] & levMasks[bitsPerValue-part-1]) << uint(part)))
}

func minInt(a, b int) int {
	if a < b {
		return a
	}
	return b
}
